 275: const signedHeaders = (method: string, path: string, secret: string, body?: unknown) => {
 276:   const timestamp = new Date().toISOString();
 277:   const nonce = `nonce-${Math.random().toString(16).slice(2)}`;
 278:   const signature = signPayload(secret, createSignaturePayload(method, path, timestamp, nonce, body));
 279: 
 280:   return {
 281:     Cookie: "sf_session=session-token; sf_workstation=binding-token",
 282:     "x-station-token": "Front-Desk-01",
 283:     "x-sf-timestamp": timestamp,
 284:     "x-sf-nonce": nonce,
 285:     "x-sf-signature": signature
 286:   };
 287: };
 288: 
 289: const joinedCookies = (headerValue: string | string[] | undefined) =>
 290:   Array.isArray(headerValue) ? headerValue.join(";") : headerValue ?? "";
