1:import { Router } from "express";
2:import type { RequestHandler, Response } from "express";
3:import { z } from "zod";
4:import { AppError } from "../errors.js";
5:import { asyncHandler, ok } from "../http.js";
6:import type { ReturnTypeOfCreateAuthService } from "../service-types.js";
7:import type { AppConfig } from "../config.js";
8:
9:const loginSchema = z.object({
10:  username: z.string().min(1),
11:  password: z.string().min(12)
12:});
13:
14:const pinSchema = z.object({
15:  pin: z.string().regex(/^\d{4,6}$/)
16:});
17:
18:const pinReentrySchema = z.object({
19:  username: z.string().min(1),
20:  pin: z.string().regex(/^\d{4,6}$/)
21:});
22:
23:const bootstrapSchema = z.object({
24:  username: z.string().min(1),
25:  fullName: z.string().min(1),
26:  password: z.string().min(12)
27:});
28:
29:export const createAuthRouter = (
30:  authService: ReturnTypeOfCreateAuthService,
31:  config: AppConfig,
32:  rateLimitedSignIn: RequestHandler,
33:  requireSignedSession: RequestHandler
34:) => {
35:  const router = Router();
36:  const cookieOptions = {
37:    httpOnly: true,
38:    sameSite: "lax" as const,
39:    secure: config.NODE_ENV === "production"
40:  };
41:  const setSessionCookies = (res: Response, sessionToken: string, workstationBindingToken: string) => {
42:    res.cookie("sf_session", sessionToken, cookieOptions);
43:    res.cookie("sf_workstation", workstationBindingToken, cookieOptions);
44:  };
45:
46:  router.get("/bootstrap/status", asyncHandler(async (_req, res) => {
47:    ok(res, await authService.getBootstrapStatus());
48:  }));
49:
50:  router.post("/bootstrap/admin", rateLimitedSignIn, asyncHandler(async (req, res) => {
51:    const input = bootstrapSchema.parse(req.body);
52:    const result = await authService.bootstrapAdministrator(
53:      input.username,
54:      input.fullName,
55:      input.password,
56:      req.stationToken ?? "Unknown-Station"
57:    );
58:
59:    setSessionCookies(res, result.session.sessionToken, result.workstationBindingToken);
60:
61:    ok(res, {
62:      currentUser: result.currentUser,
63:      sessionSecret: result.session.sessionSecret,
64:      sessionTimeoutMinutes: result.sessionTimeoutMinutes,
65:      warmLockMinutes: result.warmLockMinutes,
66:      hasPin: result.hasPin
67:    });
68:  }));
69:
70:  router.post("/login", rateLimitedSignIn, asyncHandler(async (req, res) => {
71:    const input = loginSchema.parse(req.body);
72:    const result = await authService.login(
73:      input.username,
74:      input.password,
75:      req.ip ?? req.socket.remoteAddress ?? "unknown",
76:      req.stationToken ?? "Unknown-Station"
77:    );
78:
79:    setSessionCookies(res, result.session.sessionToken, result.workstationBindingToken);
80:
81:    ok(res, {
82:      currentUser: result.currentUser,
83:      sessionSecret: result.session.sessionSecret,
84:      sessionTimeoutMinutes: result.sessionTimeoutMinutes,
85:      warmLockMinutes: result.warmLockMinutes,
86:      hasPin: result.hasPin
87:    });
88:  }));
89:
90:  router.post("/pin/setup", requireSignedSession, asyncHandler(async (req, res) => {
91:    if (!req.currentUser) {
92:      throw new AppError(401, "missing_session", "Session is required");
93:    }
94:    const input = pinSchema.parse(req.body);
95:    await authService.setupPin(req.currentUser!.id, input.pin);
96:    ok(res, { hasPin: true });
97:  }));
98:
99:  router.post("/pin/reenter", rateLimitedSignIn, asyncHandler(async (req, res) => {
100:    const input = pinReentrySchema.parse(req.body);
101:    const result = await authService.reenterWithPin(
102:      input.username,
103:      input.pin,
104:      req.cookies.sf_session as string | undefined,
105:      req.stationToken ?? "Unknown-Station",
106:      req.cookies.sf_workstation as string | undefined,
107:      req.ip ?? req.socket.remoteAddress ?? "unknown"
108:    );
109:
110:    setSessionCookies(res, result.session.sessionToken, result.workstationBindingToken);
111:
112:    ok(res, {
113:      currentUser: result.currentUser,
114:      sessionSecret: result.session.sessionSecret,
115:      sessionTimeoutMinutes: result.sessionTimeoutMinutes,
116:      warmLockMinutes: result.warmLockMinutes,
117:      hasPin: result.hasPin
118:    });
119:  }));
120:
121:  router.post("/warm-lock", requireSignedSession, asyncHandler(async (req, res) => {
122:    if (!req.currentSession) {
123:      throw new AppError(401, "missing_session", "Session is required");
124:    }
125:    await authService.warmLockSession(req.currentSession.sessionToken);
126:    ok(res, { warmLocked: true });
127:  }));
128:
129:  router.post("/logout", requireSignedSession, asyncHandler(async (req, res) => {
130:    if (!req.currentSession) {
131:      throw new AppError(401, "missing_session", "Session is required");
132:    }
133:    if (req.currentSession) {
134:      await authService.logout(req.currentSession.sessionToken);
135:    }
136:    res.clearCookie("sf_session");
137:    res.clearCookie("sf_workstation");
138:    ok(res, { loggedOut: true });
139:  }));
140:
141:  router.get("/session", asyncHandler(async (req, res) => {
142:    const sessionToken = req.cookies.sf_session as string | undefined;
143:    if (!sessionToken) {
144:      ok(res, { session: null });
145:      return;
146:    }
147:
148:    await authService.assertWorkstationBinding(
149:      sessionToken,
150:      req.cookies.sf_workstation as string | undefined
151:    );
152:    const session = await authService.getSession(sessionToken);
153:    if (!session) {
154:      ok(res, { session: null });
155:      return;
156:    }
157:
158:    const warmLocked = Boolean(session.hasPin && session.session.warmLockedAt);
159:    if (!warmLocked) {
160:      await authService.touchSession(sessionToken);
161:    }
162:
163:    ok(res, {
164:      session: {
165:        currentUser: session.currentUser,
166:        hasPin: session.hasPin,
167:        warmLocked,
168:        sessionSecret: warmLocked ? null : session.session.sessionSecret,
169:        warmLockMinutes: config.WARM_LOCK_MINUTES,
170:        sessionTimeoutMinutes: config.SESSION_TIMEOUT_MINUTES,
171:        lastActivityAt: session.session.lastActivityAt.toISOString()
172:      }
173:    });
174:  }));
175:
176:  return router;
177:};
