7:
8:const postSchema = z.object({
9:  kind: z.enum(["tip", "announcement"]),
10:  title: z.string().min(1),
11:  body: z.string().min(1),
12:  locationCode: z.string().min(1)
13:});
14:
15:const viewSchema = z.object({
16:  postId: z.number().int().positive()
17:});
18:
19:const searchSchema = z.object({
20:  searchTerm: z.string().min(1),
21:  locationCode: z.string().min(1)
22:});
23:
24:const isoDateSchema = z.string().regex(/^\d{4}-\d{2}-\d{2}$/);
25:
26:const isValidIsoDate = (value: string) => {
27:  const [yearPart, monthPart, dayPart] = value.split("-");
28:  const year = Number(yearPart);
29:  const month = Number(monthPart);
30:  const day = Number(dayPart);
31:  if (!Number.isInteger(year) || !Number.isInteger(month) || !Number.isInteger(day)) {
32:    return false;
33:  }
34:  if (month < 1 || month > 12 || day < 1 || day > 31) {
35:    return false;
36:  }
37:
38:  const utcDate = new Date(Date.UTC(year, month - 1, day));
39:  return (
40:    utcDate.getUTCFullYear() === year &&
41:    utcDate.getUTCMonth() === month - 1 &&
42:    utcDate.getUTCDate() === day
43:  );
44:};
45:
46:const analyticsQuerySchema = z.object({
47:  startDate: isoDateSchema.optional(),
48:  endDate: isoDateSchema.optional(),
49:  locationCode: z.string().min(1).max(100).optional(),
50:  includeHistorical: z
51:    .union([z.literal("true"), z.literal("false"), z.undefined()])
52:    .transform((value) => value === "true")
53:}).superRefine((value, ctx) => {
54:  if (value.startDate && !isValidIsoDate(value.startDate)) {
55:    ctx.addIssue({
56:      code: z.ZodIssueCode.custom,
57:      message: "Start date must be a valid calendar date",
58:      path: ["startDate"]
59:    });
60:  }
61:
62:  if (value.endDate && !isValidIsoDate(value.endDate)) {
63:    ctx.addIssue({
64:      code: z.ZodIssueCode.custom,
65:      message: "End date must be a valid calendar date",
66:      path: ["endDate"]
67:    });
68:  }
69:
70:  if (value.startDate && value.endDate && value.endDate < value.startDate) {
71:    ctx.addIssue({
72:      code: z.ZodIssueCode.custom,
73:      message: "End date must be on or after start date",
74:      path: ["endDate"]
75:    });
76:  }
77:});
